	require.NoError(t, err)

	mediaFiles2, err := ds.MediaFile(ctx).GetAll()
	require.NoError(t, err)
	require.Greater(t, len(mediaFiles2), 0)

	// Verify IDs are consistent
	assert.Equal(t, mediaFiles1[0].ID, mediaFiles2[0].ID, "media file IDs should be deterministic")
}

